    &CostingUnitFormShowing;


        &CostingUnitLockedBeforeEdit;

select 'setFormDefaultValue(this);' as message
return






        &CostingUnitLockedBeforeEdit;

select 'setFormDefaultValue(this);' as message
return







declare @$exists nvarchar(512), @$recordHasBeenChanged nvarchar(512)
select @$exists = case when @@language = 'v' then N'<span class="Highlight">Thông tin vật tư thay thế đang cập nhật đã được khai báo</span>, không lưu được.' else N'<span class="Highlight">This item already exists</span>, it can not be saved.' end
select @$recordHasBeenChanged = case when @@language = 'v' then N'Bản ghi hiện thời đã được sửa hoặc xóa bởi người sử dụng khác.' else N'This item has been modified or deleted by another user.' end







if (this.getItem('ma_vt').value == this.getItem('ma_vt0').value) {
  var msg = (this._language == 'v' ? 'Vật tư và nhóm vật tư thay thế không được trùng nhau.' : 'Item code and replacement item group can not be the same.');
  this._checked = false;
  $func.hideWait(this.get_id());
  $message.show(msg, String.format('$find(\'{0}\').getItem(\'ma_vt0\').focus();', this.get_id()));
}







if exists(select * from @@table where nam = @nam and ky = @ky and ma_dvcs = @ma_dvcs and ma_vt = @ma_vt and ma_vt0 = @ma_vt0)
  begin
    select 'ma_vt' as field, @$exists as message
    return
  end
select @datetime0 = getdate(), @datetime2 = getdate(), @user_id0 = @@userID, @user_id2 = @@userID







if not exists(select * from @@table where nam = $nam.OldValue and ky = $ky.OldValue and ma_dvcs = $ma_dvcs.OldValue and ma_vt = $ma_vt.OldValue and ma_vt0 = $ma_vt0.OldValue)
  begin
    select 'ma_vt' as field, @$recordHasBeenChanged as message
    return
  end

if @nam <> $nam.OldValue or @ky <> $ky.OldValue or @ma_dvcs <> $ma_dvcs.OldValue or @ma_vt <> $ma_vt.OldValue or @ma_vt0 <> $ma_vt0.OldValue 
  begin
    if exists(select * from @@table where (not (nam = $nam.OldValue and ky = $ky.OldValue and ma_dvcs = $ma_dvcs.OldValue and ma_vt = $ma_vt.OldValue and ma_vt0 = $ma_vt0.OldValue)) 
      and (nam = @nam and ky = @ky and ma_dvcs = @ma_dvcs and ma_vt = @ma_vt and ma_vt0 = @ma_vt0)) begin

      select 'ma_vt' as field, @$exists as message
      return
    end
  end







update @@table set datetime2 = getdate(), user_id2 = @@userID where nam = @nam and ky = @ky and ma_dvcs = @ma_dvcs and ma_vt = @ma_vt and ma_vt0 = @ma_vt0






        &CostingUnitLockedBeforeDelete;

script.text:

function setFormDefaultValue(f) {
  if (f._action == 'New') {
    f.setItemValue('nam', f.grid._year);
    f.setItemValue('ky', f.grid._period);
  }
  setUnitInformation(f);
}

      &CostingUnitFunction;
